const REGIONS = ['All', 'North America', 'Europe', 'Asia-Pacific', 'Crypto', 'Forex'];

const REGION_COLORS = {
  'North America': T.blue,
  'Europe': T.purple,
  'Asia-Pacific': T.amber,
  'Crypto': T.green,
  'Forex': T.cyan,
};

/* ── Broker Logo placeholder (colored circle with initials) ───────── */
function BrokerLogo({ broker, size = 48 }) {
  return (
    <div className={s.brokerLogo} style={{
      width: size, height: size,
      background: `${broker.color}18`,
      border: `1.5px solid ${broker.color}40`,
      fontSize: size * 0.28, color: broker.color,
    }}>
      {broker.logo}
    </div>
  );
}

/* ── Unofficial API badge ─────────────────────────────────────────── */
function UnofficialBadge() {
  return (
    <span className={s.unofficialBadge} title="Uses unofficial API — may violate broker ToS" style={{
      fontSize: 10, fontWeight: 700, padding: '2px 7px', borderRadius: 5,
      color: T.amber, background: `${T.amber}15`, border: `1px solid ${T.amber}35`,
      fontFamily: T.mono, letterSpacing: '0.04em',
    }}>
      UNOFFICIAL API
    </span>
  );
}

/* ── Region badge ────────────────────────────────────────────────── */
function RegionBadge({ region }) {
  const color = REGION_COLORS[region] || T.textSec;
  return (
    <span className={s.regionBadge} style={{
      color, background: `${color}12`, border: `1px solid ${color}20`,
    }}>{region}</span>
  );
}

/* ── Market pill ──────────────────────────────────────────────────── */
function MarketPill({ market }) {
  const colors = {
    Stocks: T.blue, Options: T.purple, Futures: T.amber, Forex: '#22D3EE',
    Crypto: T.green, ETFs: T.blue, CFDs: '#F97316', Bonds: '#94A3B8',
    Funds: '#94A3B8', Commodities: T.amber, Staking: T.green,
    Spot: T.green, Perpetuals: '#F59E0B', Margin: '#F97316',
    Indices: T.cyan, 'F&O': T.purple, Currency: '#22D3EE',
  };
  const c = colors[market] || T.textSec;
  return (
    <span className={s.marketPill} style={{ color: c, background: `${c}10` }}>{market}</span>
  );
}

/* ── Affiliate Earn badge ────────────────────────────────────────── */
function EarnBadge({ brokerId }) {
  const aff = AFFILIATE_DATA[brokerId];
  if (!aff) return null;
  return (
    <span className={s.earnBadge} title={aff.commission} style={{
      fontSize: 10, fontWeight: 700, padding: '2px 7px', borderRadius: 5,
      color: T.green, background: `${T.green}15`, border: `1px solid ${T.green}35`,
      fontFamily: T.mono, letterSpacing: '0.04em', cursor: 'help',
    }}>
      {aff.earn}
    </span>
  );
}

/* ── Connected badge ──────────────────────────────────────────────── */
function ConnectedBadge() {
  return (
    <span className={s.connectedBadge}>
      <span className={s.connectedDot} />
      CONNECTED
    </span>
  );
}

/* ── Broker card ──────────────────────────────────────────────────── */
function BrokerCard({ broker }) {
  return (
    <div className={s.brokerCard}
      onMouseEnter={e => { e.currentTarget.style.borderColor = broker.color + '55'; }}
      onMouseLeave={e => { e.currentTarget.style.borderColor = ''; }}
    >
      {/* Header */}
      <div className={s.cardHeader}>
        <BrokerLogo broker={broker} />
        <div className={s.cardHeaderInfo}>
          <div className={s.cardNameRow}>
            <span className={s.cardName}>{broker.name}</span>
            {broker.connected && <ConnectedBadge />}
            {broker.unofficial && <UnofficialBadge />}
            <EarnBadge brokerId={broker.id} />
          </div>
          <div className={s.cardTagline}>{broker.tagline}</div>
        </div>
      </div>

      {/* Description */}
      <div className={s.cardDescription}>{broker.description}</div>

      {/* Markets */}
      <div>
        <div className={s.sectionLabel}>Markets</div>
        <div className={s.pillRow}>
          {broker.markets.map(m => <MarketPill key={m} market={m} />)}
        </div>
      </div>

      {/* Regions */}
      <div>
        <div className={s.sectionLabel}>Available In</div>
        <div className={s.pillRow}>
          {broker.regions.map(r => (
            <span key={r} className={s.regionTag}>{r}</span>
          ))}
        </div>
      </div>

      {/* Features */}
      <div className={s.featuresSection}>
        <div className={s.sectionLabel}>Key Features</div>
        <ul className={s.featureList}>
          {broker.features.map((f, i) => (
            <li key={i} className={s.featureItem}>
              <span className={s.featureCheck}>&#10003;</span>{f}
            </li>
          ))}
        </ul>
      </div>

      {/* Connection info */}
      <div className={s.connectionInfo}>
        <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d="M10 13a5 5 0 0 0 7.54.54l3-3a5 5 0 0 0-7.07-7.07l-1.72 1.71" /><path d="M14 11a5 5 0 0 0-7.54-.54l-3 3a5 5 0 0 0 7.07 7.07l1.71-1.71" /></svg>
        <span>Connection: <strong className={s.connectionValue}>{broker.connection}</strong></span>
      </div>

      {/* Actions */}
      <div className={s.cardActions}>
        {broker.connected ? (
          <Link to="/accounts" className={s.btnManage}>Manage Connection</Link>
        ) : (
          <Link to={`/brokers/${broker.id}`} className={s.btnConnect}>Connect</Link>
        )}
        {AFFILIATE_DATA[broker.id] ? (
          <a href={`/api/referrals/link/${broker.id}`} target="_blank" rel="noopener noreferrer" className={s.btnOpenAccount}>
            Open Account
          </a>
        ) : (
          <a href={broker.url} target="_blank" rel="noopener noreferrer" className={s.btnOpenAccount}>Open Account</a>
        )}
      </div>
    </div>
  );
}

/* ── Stats strip ──────────────────────────────────────────────────── */
function StatsStrip({ connectedCount }) {
  const stats = [
    { value: '46', label: 'Supported Brokers' },
    { value: '5', label: 'Regions' },
    { value: String(connectedCount), label: 'Connected' },
    { value: '60s', label: 'Avg. Connection Time' },
  ];
  return (
    <div className={s.statsStrip}>
      {stats.map((st, i) => (
        <div key={i} className={s.statItem}>
          <div className={s.statValue}>{st.value}</div>
          <div className={s.statLabel}>{st.label}</div>
        </div>
      ))}
    </div>
  );
}

/* ── Main Page ────────────────────────────────────────────────────── */
export default function BrokersPage() {
  usePageTitle('Supported Brokers -- Aura Alpha');
  const [region, setRegion] = useState('All');
  const [search, setSearch] = useState('');
  const [connectedIds, setConnectedIds] = useState(new Set());

  // Fetch live connection status from backend on mount
  useEffect(() => {
    fetch('/api/brokers')
      .then(r => r.ok ? r.json() : null)
      .then(data => {
        if (data && Array.isArray(data)) {
          setConnectedIds(new Set(data.filter(b => b.connected).map(b => b.key || b.id)));
        }
      })
      .catch(() => { /* backend unavailable — default all disconnected */ });
  }, []);

  // Merge static broker data with live connected status
  const BROKERS = useMemo(() =>
    BROKERS_STATIC.map(b => ({ ...b, connected: connectedIds.has(b.id) })),
    [connectedIds]
  );

  const connectedCount = BROKERS.filter(b => b.connected).length;

  const filtered = useMemo(() => {
    return BROKERS.filter(b => {
      if (region !== 'All' && b.region !== region) return false;
      if (search) {
        const q = search.toLowerCase();
        return b.name.toLowerCase().includes(q)
          || b.markets.some(m => m.toLowerCase().includes(q))
          || b.regions.some(r => r.toLowerCase().includes(q));
      }
      return true;
    });
  }, [region, search, BROKERS]);

  return (
    <div className={s.pageRoot}>
      <SEO
        title="Supported Brokers -- Trade on 46+ Brokers Worldwide"
        description="Connect to 46+ brokers: Interactive Brokers, Alpaca, Schwab, Kraken, Coinbase, Bybit, OKX, OANDA, IG Group, Capital.com, and more. Trade stocks, options, futures, forex, and crypto from one platform."
        keywords="broker API, trading API, Interactive Brokers API, Alpaca API, Kraken API, OANDA API, IG Group API, Capital.com API, algorithmic trading brokers, automated trading"
      />
      <PublicNav />

      {/* ── Hero ───────────────────────────────────────────────── */}
      <section className={s.heroSection}>
        <div className={s.heroBadge}>
          <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><circle cx="12" cy="12" r="10" /><line x1="2" y1="12" x2="22" y2="12" /><path d="M12 2a15.3 15.3 0 0 1 4 10 15.3 15.3 0 0 1-4 10 15.3 15.3 0 0 1-4-10 15.3 15.3 0 0 1 4-10z" /></svg>
          GLOBAL BROKER NETWORK
        </div>

        <h1 className={s.heroTitle}>
          Trade on Any Exchange,<br />From One Platform
        </h1>

        <p className={s.heroSubtitle}>
          Connect your existing brokerage account in 60 seconds. Aura Alpha integrates
          with 46+ brokers across North America, Europe, Asia-Pacific, Crypto, and Forex.
        </p>

        {/* Region badges */}
        <div className={s.heroRegionBadges}>
          {Object.entries(REGION_COLORS).map(([r, c]) => (
            <span key={r} className={s.heroRegionBadge} style={{
              color: c, background: `${c}10`, border: `1px solid ${c}20`,
            }}>{r}</span>
          ))}
        </div>
      </section>

      {/* ── Stats ──────────────────────────────────────────────── */}
      <StatsStrip connectedCount={connectedCount} />

      {/* ── Filters ────────────────────────────────────────────── */}
      <section className={s.filterSection}>
        <div className={s.filterBar}>
          {/* Region tabs */}
          <div className={s.regionTabs}>
            {REGIONS.map(r => (
              <button key={r} onClick={() => setRegion(r)}
                className={`${s.regionTab} ${region === r ? s.regionTabActive : s.regionTabInactive}`}
              >{r === 'All' ? 'All Brokers' : r}</button>
            ))}
          </div>

          {/* Search */}
          <div className={s.searchWrapper}>
            <svg className={s.searchIcon} width="14" height="14" viewBox="0 0 24 24" fill="none" stroke={T.textSec} strokeWidth="2">
              <circle cx="11" cy="11" r="8" /><line x1="21" y1="21" x2="16.65" y2="16.65" />
            </svg>
            <input
              value={search} onChange={e => setSearch(e.target.value)}
              placeholder="Search brokers, markets..."
              className={s.searchInput}
            />
          </div>
        </div>
      </section>

      {/* ── Broker Grid ────────────────────────────────────────── */}
      <section className={s.gridSection}>
        {filtered.length === 0 ? (
          <div className={s.emptyState}>
            <div className={s.emptyTitle}>No brokers match your search</div>
            <div className={s.emptyDesc}>Try a different region or search term.</div>
          </div>
        ) : (
          <div className={s.brokersGrid}>
            {filtered.map(b => <BrokerCard key={b.id} broker={b} />)}
          </div>
        )}
      </section>

      {/* ── Already have an account? ───────────────────────────── */}
      <section className={s.ctaSection}>
        <div className={s.ctaInner}>
          <div>
            <h2 className={s.ctaTitle}>Already have a brokerage account?</h2>
            <p className={s.ctaDesc}>
              Connect your existing broker to Aura Alpha in 60 seconds. Your credentials
              stay with your broker -- we never see, store, or proxy your login.
            </p>
          </div>
          <div className={s.ctaButtons}>
            <Link to="/accounts" className={s.btnConnectNow}>Connect Now</Link>
            <Link to="/api-keys" className={s.btnApiKeys}>Manage API Keys</Link>
          </div>
        </div>
      </section>

      {/* ── How It Works ───────────────────────────────────────── */}
      <section className={s.howItWorksSection}>
        <div className={s.howItWorksHeader}>
          <h2 className={s.howItWorksTitle}>How Broker Connections Work</h2>
          <p className={s.howItWorksSubtitle}>Three simple steps to start trading on any exchange</p>
        </div>
        <div className={s.stepsRow}>
          {[
            { step: '1', title: 'Choose Your Broker', desc: 'Select from 46+ supported brokers. Use your existing account or open a new one through our partner links.', color: T.blue },
            { step: '2', title: 'Connect via API', desc: 'Enter your API key or authenticate via OAuth. Your credentials are encrypted and stored locally -- never on our servers.', color: T.purple },
            { step: '3', title: 'Start Trading', desc: 'Aura Alpha\'s strategies route orders directly to your broker. Full control with kill switches and risk limits.', color: T.green },
          ].map((st, i) => (
            <div key={i} className={s.stepCard} style={{ borderTop: `3px solid ${st.color}` }}>
              <div className={s.stepCircle} style={{ background: `${st.color}15`, color: st.color }}>{st.step}</div>
              <div className={s.stepTitle}>{st.title}</div>
              <div className={s.stepDesc}>{st.desc}</div>
            </div>
          ))}
        </div>
      </section>

      <PublicFooter />
    </div>
  );
}
